static PyObject* FNePyStruct_Vector_RichCmp(FNePyStruct_Vector* InSelf, PyObject* InOther, int InOp)
{
	switch (InOp)
	{
		case Py_EQ:
			return FNePyStruct_Vector___eq__(InSelf, InOther);
		case Py_NE:
			return FNePyStruct_Vector___ne__(InSelf, InOther);
		default:
			break;
	}

	return PyErr_Format(PyExc_NotImplementedError, "this kind of compare is not implemented by Vector");
}

bool NePyStructPropSet_Vector(const FStructProperty* InStructProp, FNePyStructBase* InSelf, void* InBuffer)
{
	if (FNePyStruct_Vector* PyObj = NePyStructCheck_Vector(InSelf))
	{
		InStructProp->Struct->CopyScriptStruct(InBuffer, PyObj->Value);
		return true;
	}
	return false;
}

FNePyStructBase* NePyStructPropGet_Vector(const FStructProperty* InStructProp, const void* InBuffer)
{
	PyTypeObject* PyType = &FNePyStructType_Vector;
	FNePyStruct_Vector* PyObj = (FNePyStruct_Vector*)PyType->tp_alloc(PyType, 0);
#if NEPY_ENABLE_STRUCT_DEEP_ACCESS
	PyObj->Value = (FVector*)InBuffer;
	PyObj->SelfCreatedValue = false;
#else
	PyObj->Value = (FVector*)FMemory::Malloc(sizeof(FVector), alignof(FVector));
	NePyBase::EnsureCopyToStructSafely<FVector>(InStructProp, PyObj->Value);
	InStructProp->Struct->CopyScriptStruct(PyObj->Value, InBuffer);
	PyObj->SelfCreatedValue = true;
#endif
	PyObj->PyOuter = nullptr;
	return PyObj;
}

PyTypeObject* NePyNePyWrappedStructInit_Vector(const UScriptStruct* InScriptStruct, PyTypeObject* InPyBase)
{
	PyTypeObject* NePyStructType = &FNePyStructType_Vector;
	TNePyStructBase<FVector>::InitTypeCommon(NePyStructType);
	NePyStructType->tp_init = (initproc)&FNePyStruct_Vector_FVector;
	NePyStructType->tp_getset = FNePyStructType_Vector_getset;
	NePyStructType->tp_methods = FNePyStructType_Vector_methods;
	static PyNumberMethods PyNumber;
	PyNumber.nb_add = (binaryfunc)&FNePyStruct_Vector___add__;
	PyNumber.nb_subtract = (binaryfunc)&FNePyStruct_Vector___sub__;
	PyNumber.nb_multiply = (binaryfunc)&FNePyStruct_Vector___mul__;
	#if PY_MAJOR_VERSION < 3
	PyNumber.nb_divide = (binaryfunc)&FNePyStruct_Vector___div__;
	#else
	PyNumber.nb_true_divide = (binaryfunc)&FNePyStruct_Vector___div__;
	#endif
	PyNumber.nb_inplace_add = (binaryfunc)&FNePyStruct_Vector___iadd__;
	PyNumber.nb_inplace_subtract = (binaryfunc)&FNePyStruct_Vector___isub__;
	PyNumber.nb_inplace_multiply = (binaryfunc)&FNePyStruct_Vector___imul__;
	#if PY_MAJOR_VERSION < 3
	PyNumber.nb_inplace_divide = (binaryfunc)&FNePyStruct_Vector___idiv__;
	#else
	PyNumber.nb_inplace_true_divide = (binaryfunc)&FNePyStruct_Vector___idiv__;
	#endif
	NePyStructType->tp_as_number = &PyNumber;
	NePyStructType->tp_richcompare = (richcmpfunc)&FNePyStruct_Vector_RichCmp;
	NePyStructType->tp_base = InPyBase;
	PyType_Ready(NePyStructType);

	if (InScriptStruct)
	{
		FNePyStructTypeInfo TypeInfo = {
			NePyStructType,
			ENePyTypeFlags::StaticPyType,
			(NePyStructPropSet)NePyStructPropSet_Vector,
			(NePyStructPropGet)NePyStructPropGet_Vector,
		};
		FNePyWrapperTypeRegistry::Get().RegisterWrappedStructType(InScriptStruct, TypeInfo);
	}

	return NePyStructType;
}

void NePyInitStruct_Vector(PyObject* PyOuterModule)
{
	FNePyWrapperInitializer::Get().RegisterWrappedStructInitFunc(
		TBaseStructure<FVector>::Get(), NePyNePyWrappedStructInit_Vector);
}

FNePyStruct_Vector* NePyStructNew_Vector(const FVector& InValue)
{
	PyTypeObject* PyType = &FNePyStructType_Vector;
	FNePyStruct_Vector* RetValue = (FNePyStruct_Vector*)PyType->tp_alloc(PyType, 0);
	if (FNePyStruct_Vector::Init(RetValue, nullptr, nullptr) < 0)
	{
		Py_DECREF(RetValue);
		return nullptr;
	}
	new(RetValue->Value) FVector(InValue);
	return RetValue;
}

FNePyStruct_Vector* NePyStructCheck_Vector(PyObject* InPyObj)
{
	if (InPyObj && PyObject_TypeCheck(InPyObj, &FNePyStructType_Vector))
	{
		return (FNePyStruct_Vector*)InPyObj;
	}
	return nullptr;
}

PyTypeObject* NePyStructGetType_Vector()
{
	return &FNePyStructType_Vector;
}

namespace NePyBase
{
	bool ToCpp(PyObject* InPyObj, FVector& OutVal)
	{
		if (FNePyStruct_Vector* PyObj = NePyStructCheck_Vector(InPyObj))
		{
			OutVal = *(FVector*)PyObj->Value;
			return true;
		}
		return false;
	}

	bool ToPy(const FVector& InVal, PyObject*& OutPyObj)
	{
		OutPyObj = NePyStructNew_Vector(InVal);
		return true;
	}
}
